 8	/**
 9	 *  Returns the sum of a list of integers using forward accumulation.
10	 *  The input parameter is not used ("nu").
11	 * @author Son Nguyen and Charlie Lockyer
12	 *
13	 */
14	public class LastFwdAlgo implements IListAlgo {
15		private final IListAlgo helper = new IListAlgo() {
16			@Override
17			public Object emptyCase(MTList host, Object... acc) {
18				return acc[0];
19			}
20	
21			@Override
22			public Object nonEmptyCase(NEList host, Object... acc) {
23				return host.getRest().execute(this, host.getFirst());
24			}
25		};
26	
27		@Override
28		/**
29		 * The base case value is null,
30		 */
31		public Object emptyCase(MTList host, Object... nu) {
32			return null;
33		}
34	
35		@Override
36		/**
37		 * Pass the first value to the rest of the list, using a helper visitor, to be accumulated.
38		 */
39		public Object nonEmptyCase(NEList host, Object... nu) {
40			return host.getRest().execute(helper, host.getFirst());
41		}
42	
43	}

