 7	/**
 8	 * Returns the boolean value if a param is in a list of integers using reverse accumulation.
 9	 * The input parameter is not used ("nu").
10	 */
11	public class SearchRevAlgo implements IListAlgo {
12		/**
13		 * Returns zero always.
14		 */
15		public Object emptyCase(MTList host, Object... nu) {
16			return false;
17		}
18	
19		/**
20		 * Returns first plus the result of the rest of the list.
21		 */
22		public Object nonEmptyCase(NEList host, Object... param) {
23			int target = Integer.parseInt((String) param[0]);
24			return ((Integer) host.getFirst() == target) || ((Boolean) host.getRest().execute(this, param));
25		}
26	
27	}

