 3	import provided.listFW.IList;
 4	import provided.listFW.IListAlgo;
 5	import provided.listFW.MTList;
 6	import provided.listFW.NEList;
 7	
 8	/**
 9	 * Return a list with the smallest element from the list removed.
10	 * Do this with a single pass through the the list!
11	 * The input parameter is not used ("nu").
12	 * @author Son Nguyen and Charlie Lockyer
13	 */
14	public class RemoveSmallestRevAlgo implements IListAlgo {
15		private static class MinListState {
16			private final int min;
17			private final IList listWithMinRemoved;
18			private final IList originalList;
19	
20			private MinListState(int min, IList listWithMinRemoved, IList originalList) {
21				this.min = min;
22				this.listWithMinRemoved = listWithMinRemoved;
23				this.originalList = originalList;
24			}
25		}
26	
27		private final IListAlgo helper = new IListAlgo() {
28			@Override
29			public Object emptyCase(MTList host, Object... nu) {
30				return new MinListState(Integer.MAX_VALUE, MTList.Singleton, MTList.Singleton);
31			}
32	
33			@Override
34			public Object nonEmptyCase(NEList host, Object... nu) {
35				MinListState restState = (MinListState) host.getRest().execute(this);
36				int first = (Integer) host.getFirst();
37				IList rebuiltOriginal = new NEList(first, restState.originalList);
38	
39				if (first <= restState.min) {
40					return new MinListState(first, restState.originalList, rebuiltOriginal);
41				}
42				return new MinListState(restState.min, new NEList(first, restState.listWithMinRemoved), rebuiltOriginal);
43			}
44		};
45		/**
46		 * Returns Min_value always.
47		 */
48		public Object emptyCase(MTList host, Object... nu) {
49			return MTList.Singleton;
50		}
51	
52		/**
53		 * Returns the list depending if the condition has been met.
54		 */
55		public Object nonEmptyCase(NEList host, Object... nu) {
56			return ((MinListState) host.execute(helper)).listWithMinRemoved;
57		}
58	
59	}

