 7	/**
 8	 * Returns the sum of a list of integers using reverse accumulation starting from nth.
 9	 * The input parameter is not used ("nu").
10	 */
11	public class FromNthAlgo implements IListAlgo {
12		/**
13		 * Returns zero always.
14		 */
15		public Object emptyCase(MTList host, Object... nu) {
16			return 0;
17		}
18	
19		/**
20		 * Returns first plus the sum of the rest of the list.
21		 */
22		public Object nonEmptyCase(NEList host, Object... params) {
23			int n = Integer.parseInt((String) params[0]);
24			if (n <= 1) {
25				return (Integer) host.getFirst() + (Integer) host.getRest().execute(this, "1");
26			}
27			return host.getRest().execute(this, Integer.toString(n - 1));
28		}
29	
30	}
